-- Database Schema for Bible Pro App\n\n-- Bible Content Tables\nCREATE TABLE books (\n    book_id SERIAL PRIMARY KEY,\n    name VARCHAR(255) NOT NULL,\n    testament VARCHAR(50) NOT NULL\n);\n\nCREATE TABLE chapters (\n    chapter_id SERIAL PRIMARY KEY,\n    book_id INT NOT NULL,\n    chapter_number INT NOT NULL,\n    FOREIGN KEY (book_id) REFERENCES books(book_id)\n);\n\nCREATE TABLE verses (\n    verse_id SERIAL PRIMARY KEY,\n    chapter_id INT NOT NULL,\n    verse_number INT NOT NULL,\n    text TEXT NOT NULL,\n    FOREIGN KEY (chapter_id) REFERENCES chapters(chapter_id)\n);\n\n-- Greek/Hebrew Study Tables\nCREATE TABLE original_languages (\n    language_id SERIAL PRIMARY KEY,\n    name VARCHAR(100) NOT NULL\n);\n\nCREATE TABLE word_studies (\n    study_id SERIAL PRIMARY KEY,\n    word VARCHAR(100) NOT NULL,\n    language_id INT NOT NULL,\n    definition TEXT NOT NULL,\n    FOREIGN KEY (language_id) REFERENCES original_languages(language_id)\n);\n\n-- Theological Resources Tables\nCREATE TABLE resources (\n    resource_id SERIAL PRIMARY KEY,\n    title VARCHAR(255) NOT NULL,\n    type VARCHAR(100) NOT NULL,\n    category VARCHAR(100),\n    url VARCHAR(255)\n);\n\n-- User Data Tables\nCREATE TABLE users (\n    user_id SERIAL PRIMARY KEY,\n    username VARCHAR(100) UNIQUE NOT NULL,\n    email VARCHAR(255) UNIQUE NOT NULL,\n    hashed_password VARCHAR(255) NOT NULL\n);\n\nCREATE TABLE user_preferences (\n    preference_id SERIAL PRIMARY KEY,\n    user_id INT NOT NULL,\n    preference_name VARCHAR(100) NOT NULL,\n    preference_value VARCHAR(255),\n    FOREIGN KEY (user_id) REFERENCES users(user_id)\n);\n\n-- Create necessary indexes\nCREATE INDEX idx_books_testament ON books (testament);\nCREATE INDEX idx_users_username ON users (username);\nCREATE INDEX idx_resources_category ON resources (category);\n